import os,re
roots=['src/main/java','src/test/java','src/test-jdk17/java','src/test-jdk21/java','src/test-jdk11/java']
files=[]
for root in roots:
    if os.path.isdir(root):
        for dp,_,fs in os.walk(root):
            for f in fs:
                if f.endswith('.java'): files.append(os.path.join(dp,f))
method_re=re.compile(r'(?:(?:public|protected|private|static|final|abstract|native|synchronized)\\s+)*(?:<["'^;{}()]+>'"\\s*)?[\\w"'$<>?'"\\[\\].,\\s]+\\s+(serialize)\\s*\\(',re.M)
for path in files:
    s=open(path,encoding='utf-8').read()
    # strip comments? leave
    for m in method_re.finditer(s):
        # get params balanced
        i=m.end()-1; depth=0; j=i
        while j<len(s):
            c=s[j]
            if c=='(': depth+=1
            elif c==')':
                depth-=1
                if depth==0: break
            j+=1
        params=s[i+1:j]
        if 'JsonGenerator' in params and 'SerializerProvider' in params:
            # split top commas
            parts=[]; cur=''; d=0
            for c in params:
                if c in '<({[': d+=1
                elif c in '>)}]': d-=1
                if c==',' and d==0:
                    parts.append(cur.strip()); cur=''
                else: cur+=c
            parts.append(cur.strip())
            if len(parts)==3 and 'JsonGenerator' in parts[1] and 'SerializerProvider' in parts[2]:
                # class name before pos
                prefix=s[:m.start()]
                classes=re.findall(r'\\b(?:class|interface|enum)\\s+(\\w+)', prefix)
                cls=classes[-1] if classes else ''
                print(f\"{path}:serialize:{cls}:{s.count(chr(10),0,m.start())+1}:{params.replace(chr(10),' ')}\")
PY"

