            WritableTypeId typeIdDef = typeSer0.writeTypePrefix(gen,
                    typeSer0.typeId(bean, JsonToken.VALUE_STRING));
            ser.serialize(value, gen, ctxt);
            typeSer0.writeTypeSuffix(gen, typeIdDef);

